queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasTopics ?child ; p:hasHealth_Reporters ?parent . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Health_Reporters } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?name2 WHERE {
  ?health_reporters_topics a :Health_Reporters_Topics .
  ?topics a :topics .
  ?health_reporters_topics p:hasTopics ?topics .
  ?health_reporters a :Health_Reporters .
  ?health_reporters_topics p:hasHealth_Reporters ?health_reporters .
  ?health_reporters p:name ?name .
  ?topics p:name ?name2 .
} }
  collective: { SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasTopics ?child ; p:hasHealth_Reporters ?parent . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Health_Reporters } }
  FILTER(?nf = ?total)
} }
}
